import{_ as t,o as i,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"63. Best Practice Employment Commitment Committee","description":"","frontmatter":{"title":"63. Best Practice Employment Commitment Committee","eba":"Medical Specialists 2022-2026","topics":["union-matters","preliminary","staffing","workload"]},"headers":[],"relativePath":"ebas/medical-specialists/union-matters/63-best-practice-employment-commitment-committee.md","filePath":"ebas/medical-specialists/union-matters/63-best-practice-employment-commitment-committee.md"}'),a={name:"ebas/medical-specialists/union-matters/63-best-practice-employment-commitment-committee.md"};function s(r,e,m,c,p,l){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_63-best-practice-employment-commitment-committee" tabindex="-1">63. Best Practice Employment Commitment Committee <a class="header-anchor" href="#_63-best-practice-employment-commitment-committee" aria-label="Permalink to &quot;63. Best Practice Employment Commitment Committee&quot;">​</a></h1><p><strong>63.1</strong> The parties agree to establish a committee to discuss Best Practice Employment Commitments (BPEC) during the life of the Agreement on matters including:</p><p><strong>(a)</strong> measures to identify and respond to workload including:</p><p><strong>(i)</strong> Discussion regarding reports and activities relevant to workforce planning; and</p><p><strong>(ii)</strong> Invite additional attendees to discuss workforce matters;</p><p><strong>(b)</strong> climate change initiatives to reduce carbon and other harmful emissions within the public health system including:</p><p><strong>(i)</strong> discussion regarding the environmental performance of Employers published in accordance with the Department’s environmental guidelines;</p><p><strong>(ii)</strong> discussion regarding any reports or activities of other bodies such as Global Green and Healthy Hospitals that are relevant to the reduction of carbon emissions;</p><p><strong>(iii)</strong> promotion of initiatives taken by an Employer and / or Doctors to reduce carbon and other harmful emissions; and</p><p><strong>(iv)</strong> invite external interest groups, unions or other organisations to discuss the impacts the public health system as a whole has on producing harmful emissions and any initiatives to reduce these;</p><p><strong>(c)</strong> the development of an agreed ‘best practice guide’ with respect to workplace bullying based on WorkSafe’s ‘Guide for Employers’ dated March 2020;</p><p><strong>(d)</strong> template change impact statements;</p><p><strong>(e)</strong> collaboration between the parties to reduce duplication of training and promote recognition of training across Health Services;</p><p><strong>(f)</strong> collaboration between the parties to monitor onboarding and credentialing practices to identify opportunities for common application requirements and the implementation of electronic onboarding and credentialing;</p><p>Plain language terms: BPEC.</p>',15)])])}const h=t(a,[["render",s]]);export{g as __pageData,h as default};
